import { Component, Input, OnChanges, SimpleChanges, ViewChild, ElementRef, AfterViewChecked } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReadyQueueSnapshot, EventLog } from '../../models/scheduling.model';
import { Process } from '../../models/process.model';

type EventDisplayType = 'info' | 'arrival' | 'departure' | 'switch' | 'io' | 'preempt';

@Component({
  selector: 'app-ready-queue',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './ready-queue.component.html',
  styleUrls: ['./ready-queue.component.scss']
})
export class ReadyQueueComponent implements OnChanges, AfterViewChecked {
  @Input() snapshot: ReadyQueueSnapshot | null = null;
  @Input() processes: Process[] = [];
  @Input() events: EventLog[] = [];
  @Input() currentTime: number = 0;
  @Input() isMlfq: boolean = false;
  @Input() animationMode: boolean = false;

  @ViewChild('eventsContainer') private eventsContainer!: ElementRef;

  private shouldScroll: boolean = false;

  readonly mlfqQuantums = [2, 4, 8];
  readonly mlfqBorderColors = ['#22c55e', '#eab308', '#ef4444'];
  readonly mlfqBgColors = ['rgba(34, 197, 94, 0.08)', 'rgba(234, 179, 8, 0.08)', 'rgba(239, 68, 68, 0.08)'];

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['events']) {
      this.shouldScroll = true;
    }
  }

  ngAfterViewChecked(): void {
    if (this.shouldScroll && this.eventsContainer) {
      this.eventsContainer.nativeElement.scrollTop = this.eventsContainer.nativeElement.scrollHeight;
      this.shouldScroll = false;
    }
  }

  getProcessColor(processId: number): string {
    const process = this.processes.find(p => p.id === processId);
    return process?.color || '#6c757d';
  }

  getProcessName(processId: number): string {
    const process = this.processes.find(p => p.id === processId);
    return process ? `P${processId}(${process.name})` : `P${processId}`;
  }

  getCurrentProcessId(): number | null {
    return this.snapshot?.currentProcessId ?? null;
  }

  getReadyQueue(): number[] {
    if (!this.snapshot || !this.snapshot.queues || this.snapshot.queues.length === 0) {
      return [];
    }
    return this.snapshot.queues[0] || [];
  }

  getMlfqQueue(index: number): number[] {
    if (!this.snapshot || !this.snapshot.queues) {
      return [];
    }
    return this.snapshot.queues[index] || [];
  }

  getEventType(event: EventLog): EventDisplayType {
    const msg = event.message;
    if (msg.includes('到达') || msg.includes('进入就绪队列')) {
      return 'arrival';
    }
    if (msg.includes('执行完成') || msg.includes('完成')) {
      return 'departure';
    }
    if (msg.includes('调度') || msg.includes('时间片用完')) {
      return 'switch';
    }
    if (msg.includes('IO') || msg.includes('开始IO') || msg.includes('IO完成')) {
      return 'io';
    }
    if (msg.includes('抢占')) {
      return 'preempt';
    }
    return 'info';
  }

  getEventsUpToCurrentTime(): EventLog[] {
    return this.events.filter(e => e.time <= this.currentTime);
  }

  isLatestEvent(index: number): boolean {
    const filtered = this.getEventsUpToCurrentTime();
    return index === filtered.length - 1;
  }
}
<div class="ready-queue-container">
  <div class="left-panel">
    <div class="section current-process-section">
      <h3 class="section-title">当前执行</h3>
      <div class="current-process-box">
        <ng-container *ngIf="getCurrentProcessId() !== null; else idleTemplate">
          <div
            class="process-block large"
            [ngClass]="{ 'animate-highlight': animationMode }"
            [style.backgroundColor]="getProcessColor(getCurrentProcessId()!)"
          >
            <span class="process-label">{{ getProcessName(getCurrentProcessId()!) }}</span>
          </div>
        </ng-container>
        <ng-template #idleTemplate>
          <div class="process-block large idle-block">
            <span class="process-label">CPU空闲</span>
          </div>
        </ng-template>
      </div>
    </div>

    <div class="section queues-section">
      <ng-container *ngIf="!isMlfq; else mlfqTemplate">
        <h3 class="section-title">就绪队列</h3>
        <div class="queue-container">
          <div class="queue-direction-label">队首 →</div>
          <div class="queue-list">
            <ng-container *ngIf="getReadyQueue().length > 0; else emptyQueueTemplate">
              <div
                *ngFor="let pid of getReadyQueue(); let first = first"
                class="process-item-wrapper"
              >
                <div
                  class="process-block small"
                  [ngClass]="{ 'animate-highlight': animationMode && first }"
                  [style.backgroundColor]="getProcessColor(pid)"
                >
                  <span class="process-label-small">P{{ pid }}</span>
                </div>
                <div class="queue-arrow" *ngIf="!first">←</div>
              </div>
            </ng-container>
            <ng-template #emptyQueueTemplate>
              <span class="empty-queue-text">（空）</span>
            </ng-template>
          </div>
        </div>
      </ng-container>

      <ng-template #mlfqTemplate>
        <div class="mlfq-queues">
          <div
            *ngFor="let quantum of mlfqQuantums; let i = index"
            class="mlfq-queue-wrapper"
            [style.borderColor]="mlfqBorderColors[i]"
            [style.backgroundColor]="mlfqBgColors[i]"
          >
            <h3 class="section-title mlfq-title" [style.color]="mlfqBorderColors[i]">
              第{{ i + 1 }}级队列 (时间片={{ quantum }})
            </h3>
            <div class="queue-container">
              <div class="queue-direction-label">队首 →</div>
              <div class="queue-list">
                <ng-container *ngIf="getMlfqQueue(i).length > 0; else mlfqEmptyTemplate">
                  <div
                    *ngFor="let pid of getMlfqQueue(i); let first = first"
                    class="process-item-wrapper"
                  >
                    <div
                      class="process-block small"
                      [ngClass]="{ 'animate-highlight': animationMode && first }"
                      [style.backgroundColor]="getProcessColor(pid)"
                    >
                      <span class="process-label-small">P{{ pid }}</span>
                    </div>
                    <div class="queue-arrow" *ngIf="!first">←</div>
                  </div>
                </ng-container>
                <ng-template #mlfqEmptyTemplate>
                  <span class="empty-queue-text">（空）</span>
                </ng-template>
              </div>
            </div>
          </div>
        </div>
      </ng-template>
    </div>
  </div>

  <div class="right-panel">
    <div class="section events-section">
      <h3 class="section-title">事件日志</h3>
      <div class="events-container" #eventsContainer>
        <div
          *ngFor="let event of getEventsUpToCurrentTime(); let i = index"
          class="event-item"
          [ngClass]="'event-' + getEventType(event)"
          [class.event-latest]="isLatestEvent(i) && animationMode"
        >
          <span class="event-time">[时刻{{ event.time }}]</span>
          <span class="event-message">{{ event.message }}</span>
        </div>
        <div *ngIf="getEventsUpToCurrentTime().length === 0" class="no-events">
          暂无事件日志
        </div>
      </div>
    </div>
  </div>
</div>
